  1→import { useInfiniteQuery, useQuery } from '@tanstack/react-query';
  2→import '../ProfilePage/myprofile.css';
  3→import './visitProfile.css';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getFollowsData, getUserData, getUserJournals, getUserByUsername } from '../../../API/Api';
  6→import { Fragment, useEffect, useRef } from 'react';
  7→import { Outlet, useLocation, useNavigate, useParams } from 'react-router-dom';
  8→import Sidebar from '../SideBar/Sidebar';
  9→import { MoonLoader } from 'react-spinners';
 10→import { useFollowMutation } from '../../utils/useMutation';
 11→import debounce from '../../../helpers/debounce';
 12→import VerifiedBadge from '../Badge/VerifiedBadge';
 13→import formatCounts from '../../../helpers/fomatCounts';
 14→import MobileNavlink from '../mobileNavLink/MobileNavLink';
 15→import MobileSidebarLink from '../MobileSidebarLink/MobileSidebarLink';
 16→import { useState } from 'react';
 17→import WriteJournalButton from '../WriteJournalButton/WriteJournalButton';
 18→import Editor from '../HomePage/Editor/Editor';
 19→import Loader from '../loadingComponent/BgLoader';
 20→import useProfileSeo from '../../seo/useProfileSeo';
 21→import { createProfileSidebarLinks } from '../ProfilePage/constants/profileSidebarLinks';
 22→import ShareMenu from '../ShareMenu/ShareMenu';
 23→import { getProfileShareUrl } from '../../utils/getShareUrl';
 24→import StreakBadge from '../Streak/StreakBadge';
 25→import useStreakData from '../Streak/useStreakData';
 26→
 27→const Visitprofile = () =>{
 28→    const location = useLocation();
 29→    const stateData = location.state;
 30→    const { username: urlUsername } = useParams();
 31→    const queryUserId = new URLSearchParams(location.search).get('userId');
 32→    const isUsernameRoute = !!urlUsername;
 33→
 34→    // Fetch user by username if on /@username route
 35→    const { data: usernameData, isLoading: isLoadingByUsername } = useQuery({
 36→        queryKey: ['userByUsername', urlUsername],
 37→        queryFn: () => getUserByUsername(urlUsername),
 38→        enabled: isUsernameRoute,
 39→        staleTime: 1000 * 60 * 5,
 40→        refetchOnWindowFocus: false,
 41→    });
 42→
 43→    // Resolve visitedUserId from either username lookup, state, or query param
 44→    const visitedUserId = isUsernameRoute
 45→        ? usernameData?.userData?.[0]?.id
 46→        : (stateData?.userId || queryUserId);
 47→
 48→    const resolvedUsername = isUsernameRoute
 49→        ? urlUsername
 50→        : usernameData?.userData?.[0]?.username;
 51→
 52→    const {session, user, notifCount, loading} = useAuth();
 53→
 54→    const [showSidebar, setShowSidebar]= useState(false)
 55→    const [opendRichTextEditor, setOpenRichTextEditor] = useState(false);
 56→    const [showShareMenu, setShowShareMenu] = useState(false);
 57→
 58→    const { data: visitedStreakData } = useStreakData(visitedUserId);
 59→    const buttonRef = useRef();
 60→
 61→    const navigate = useNavigate();
 62→    const visitedProfileNavState = { userId: visitedUserId };
 63→    const visibleProfileSections = [{id: 'stats'}, {id: 'bio'}, {id: 'joined_date'}];
 64→
 65→    // Use @username paths when available, fall back to legacy /visitProfile paths
 66→    const profileUsername = resolvedUsername || usernameData?.userData?.[0]?.username;
 67→    const useNewUrls = !!profileUsername;
 68→    const tablists = useNewUrls
 69→        ? [
 70→            {label: 'Writings', path: `/u/${profileUsername}`, action: () => navigate(`/u/${profileUsername}`, {state: visitedProfileNavState})},
 71→            {label: 'Media', path: `/u/${profileUsername}/media`, action: () => navigate(`/u/${profileUsername}/media`, {state: visitedProfileNavState})},
 72→            {label: 'Collections', path: `/u/${profileUsername}/collections`, action: () => navigate(`/u/${profileUsername}/collections`, {state: visitedProfileNavState})},
 73→            {label: 'Opinions', path: `/u/${profileUsername}/opinions`, action: () => navigate(`/u/${profileUsername}/opinions`, {state: visitedProfileNavState})},
 74→            {label: 'Stories', path: `/u/${profileUsername}/stories`, action: () => navigate(`/u/${profileUsername}/stories`, {state: visitedProfileNavState})}
 75→        ]
 76→        : [
 77→            {label: 'Writings', path: '/visitProfile', action: () => navigate(`/visitProfile?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 78→            {label: 'Media', path: '/visitProfile/media', action: () => navigate(`/visitProfile/media?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 79→            {label: 'Collections', path: '/visitProfile/visitedCollections', action: () => navigate(`/visitProfile/visitedCollections?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 80→            {label: 'Opinions', path:'/visitProfile/visitedOpinions', action: () => navigate(`/visitProfile/visitedOpinions?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 81→            {label: 'Stories', path:'/visitProfile/stories', action: () => navigate(`/visitProfile/stories?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})}
 82→        ]
 83→
 84→     const navigatePath = (path) => {
 85→        return navigate(path)
 86→    }
 87→
 88→    const handleMouseMove = (isFollowing) =>{
 89→        if(buttonRef.current){
 90→            if(isFollowing){
 91→                buttonRef.current.innerText = 'Unfollow'
 92→            } else {
 93→                return
 94→            }
 95→        }
 96→    }
 97→
 98→    //open rich text editor
 99→    const handleClickRichtextEditor = () =>{
100→        setOpenRichTextEditor(true);
101→    }
102→    //close rich text editor
103→    const handleCloseRichtextEditor = () =>{
104→        setOpenRichTextEditor(false);
105→    }
106→
107→    // open sidebar through boolean function
108→    const openSidebar = () =>{
109→        setShowSidebar(true)
110→    }
111→
112→    // close sidebar through boolean function
113→    const closeSidebar = () =>{
114→        setShowSidebar(false)
115→    }
116→
117→    const handleMouseLeave = (isFollowing) =>{
118→        if(buttonRef.current){
119→            if(isFollowing){
120→                buttonRef.current.innerText = 'Following'
121→            } else {
122→                return
123→            }
124→        }
125→    }
126→
127→    const mutationFollow = useFollowMutation(session);
128→    const hadnleClickFollow = (e, followingId, followerId,) =>{
129→        mutationFollow.mutate({followingId, followerId})
130→    }
131→    const debounceClickFollow = debounce(hadnleClickFollow, 0)
132→
133→    const links = createProfileSidebarLinks({
134→        location,
135→        navigatePath,
136→        navigate,
137→        notifCount,
138→        setShowEditor: setOpenRichTextEditor,
139→    });
140→
141→    
142→    const {data, isLoading} = useQuery({
143→        queryKey: ['visitedProfile', visitedUserId],
144→        queryFn:({queryKey}) => getUserData(queryKey[1]),
145→        enabled: !!visitedUserId && !isUsernameRoute,
146→        refetchOnWindowFocus: false,
147→        staleTime: 1000 * 60 * 10
148→    })
149→
150→    // Use username-fetched data when on /@username route, otherwise use userId-fetched data
151→    const userData = isUsernameRoute
152→        ? usernameData?.userData?.[0]
153→        : data?.userData?.[0]
154→
155→    useProfileSeo(userData, profileUsername);
156→    const getProfileSectionSize = () => 'md';
157→
158→    const{data: followsData, isLoading: isLoadingFollowsData} = useQuery({
159→        queryKey: ['followsData', user?.userData?.[0].id, visitedUserId],
160→        queryFn: ({queryKey}) => getFollowsData(queryKey[1], queryKey[2]),
161→        staleTime: 1000 * 60 * 60,
162→        cacheTime: 1000 * 60 * 60,
163→        enabled: !!user?.userData?.[0].id && !!visitedUserId,
164→        refetchOnWindowFocus: false
165→    })
166→
167→
168→    useEffect(() =>{
169→        console.log(data)
170→    }, [data])
171→
172→    useEffect(() => {
173→        if(!session && !loading){
174→            return navigate('/login')
175→            //check if the user has user metadata on the users table database if not then show a UI that let them input there data and save to database
176→        }
177→    
178→    },[session, loading])
179→
180→    if(isLoading || isLoadingByUsername){
181→        return(
182→            <Loader/>
183→        )
184→    }
185→    return(
186→        <>{opendRichTextEditor &&(
187→            <Editor onClose={handleCloseRichtextEditor}/>
188→        )}
189→        
190→        <div className='profile-parent-container'>
191→            {userData?.background && (
192→                <div className="blurred-img-bg" style={userData?.background}/>
193→            )}
194→
195→            <div className="side-bar-holder-container">
196→                <Sidebar links={links}/> {/*passing the setShowEditor to this component to be used as a state setter inside this component*/}
197→            </div>
198→
199→            <div style={{color: userData?.profile_font_color}} className="profile-center-bar-container">
200→                {userData && (
201→
202→                    <div style={userData?.background} className='visit-profile-hero-section'>
203→
204→                        <div className='visited-profile-top-row'>
205→                            <div className={`profile-avatar-ring ${userData?.badge === 'legend' ? 'badge-ring-legend' : userData?.badge === 'og' ? 'badge-ring-og' : ''}`}>
206→                                <img className='visited-profile-image' src={userData?.image_url || '/assets/profile.jpg'} alt={`${userData?.name || "User"} profile picture`} />
207→                            </div>
208→                        </div>
209→
210→                        <div className='visited-profile-name-container'>
211→                            <div className='visited-profile-name-row'>
212→                                <p className='visited-profile-name'>{userData?.name}</p>
213→                                <VerifiedBadge badge={userData?.badge} size={22} />
214→                                <StreakBadge count={visitedStreakData?.current_streak} size={18} />
215→                                {userData?.badge && (
216→                                    <span className={`badge-pill ${userData.badge === 'legend' ? 'badge-pill-legend' : 'badge-pill-og'}`}>
217→                                        {userData.badge === 'legend' ? 'Legend' : 'OG'}
218→                                    </span>
219→                                )}
220→                            </div>
221→                            {(profileUsername || userData?.username) && (
222→                                <p className="visited-profile-handle">@{profileUsername || userData.username}</p>
223→                            )}
224→                        </div>
225→
226→                        <div className='visited-profile-layout-sections'>
227→                            {visibleProfileSections.map((section) => {
228→                                const sectionSize = getProfileSectionSize(section.id);
229→
230→                                if(section.id === 'stats'){
231→                                    return (
232→                                        <Fragment key={section.id}>
233→                                            <div className={`visited-profile-stats-container profile-section-size-${sectionSize}`}>
234→                                                <div className='visited-profile-stat-item'>
235→                                                    <span className='visited-stat-number'>{formatCounts(followsData?.followersCount)}</span>
236→                                                    <span className='visited-stat-label'>Followers</span>
237→                                                </div>
238→                                                <div className='visited-profile-stat-item'>
239→                                                    <span className='visited-stat-number'>{formatCounts(followsData?.followingsCount)}</span>
240→                                                    <span className='visited-stat-label'>Following</span>
241→                                                </div>
242→                                            </div>
243→                                        </Fragment>
244→                                    );
245→                                }
246→
247→                                if(section.id === 'bio'){
248→                                    return (
249→                                        <Fragment key={section.id}>
250→                                            <div className={`visited-profile-bio-container profile-section-size-${sectionSize}`}>
251→                                                <p style={{margin: 0, padding: 0}}>{userData?.bio}</p>
252→                                            </div>
253→                                        </Fragment>
254→                                    );
255→                                }
256→
257→                                if(section.id === 'joined_date'){
258→                                    return (
259→                                        <Fragment key={section.id}>
260→                                            <div className={`visited-profile-joined-date profile-section-size-${sectionSize}`}>
261→                                                <p className='visited-profile-date-joined'>{new Date(userData?.created_at).toLocaleDateString('en-US', {
262→                                                    month: 'long',
263→                                                    day: '2-digit',
264→                                                    year: 'numeric'
265→                                                })}</p>
266→                                            </div>
267→                                        </Fragment>
268→                                    );
269→                                }
270→
271→                                return null;
272→                            })}
273→                        </div>
274→
275→                        <div className='visited-profile-actions-row'>
276→                            <div onMouseMove={() => handleMouseMove(followsData?.isFollowing)} onMouseLeave={() => handleMouseLeave(followsData?.isFollowing)} className='visited-profile-follow-button-container'>
277→                                <button onClick={(e) => debounceClickFollow(e, visitedUserId, user?.userData?.[0].id)} ref={buttonRef} className={followsData?.isFollowing ? 'unfollow-visited-profile-bttn' : 'follow-visited-profile-bttn'}>
278→                                    {followsData?.isFollowing ? 'Following' : 'Follow'}
279→                                </button>
280→                            </div>
281→                            {(profileUsername || userData?.username) && (
282→                                <div className="visit-profile-share-btn" style={{ position: 'relative' }} onClick={(e) => { e.stopPropagation(); setShowShareMenu((v) => !v); }}>
283→                                    <svg xmlns="http://www.w3.org/2000/svg" height="18px" viewBox="0 0 24 24" width="18px" fill="currentColor">
284→                                        <path d="M18 16.08c-.76 0-1.44.3-1.96.77L8.91 12.7c.05-.23.09-.46.09-.7s-.04-.47-.09-.7l7.05-4.11c.54.5 1.25.81 2.04.81 1.66 0 3-1.34 3-3s-1.34-3-3-3-3 1.34-3 3c0 .24.04.47.09.7L8.04 9.81C7.5 9.31 6.79 9 6 9c-1.66 0-3 1.34-3 3s1.34 3 3 3c.79 0 1.5-.31 2.04-.81l7.12 4.16c-.05.21-.08.43-.08.65 0 1.61 1.31 2.92 2.92 2.92 1.61 0 2.92-1.31 2.92-2.92s-1.31-2.92-2.92-2.92z"/>
285→                                    </svg>
286→                                    {showShareMenu && (
287→                                        <ShareMenu
288→                                            url={getProfileShareUrl(profileUsername || userData.username)}
289→                                            title={`${userData.name || profileUsername || userData.username}'s Profile`}
290→                                            onClose={() => setShowShareMenu(false)}
291→                                        />
292→                                    )}
293→                                </div>
294→                            )}
295→                        </div>
296→
297→                    </div>
298→
299→                    )
300→                }
301→
302→                <div className='my-profile-tablist'>
303→                    {tablists.map((tab, index) => (
304→                         <div key={index} onClick={() => tab.action()} className='tab-container'>
305→                            {tab.label}
306→                            <div className={location.pathname === tab.path ? 'tab-indicator' : ''}/>
307→                        </div>
308→                    ))}
309→                   
310→                </div>
311→
312→                <Outlet/>
313→
314→            </div>
315→            
316→            <div className="profile-sidebar-right-holder-container" />
317→
318→            {showSidebar && (
319→                <MobileSidebarLink onclose={closeSidebar}/>
320→            )}
321→            
322→            {<MobileNavlink clickOpenSidebar={openSidebar}/>}
323→            <WriteJournalButton onOpen={handleClickRichtextEditor}/>
324→        </div>
325→        </>
326→
327→    )
328→}
329→export default Visitprofile;
